import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import io from 'socket.io-client';
import {
  Box,
  Paper,
  TextField,
  IconButton,
  Avatar,
  Typography,
  List,
  ListItem,
  ListItemAvatar,
  ListItemText,
  Badge,
  Chip,
  CircularProgress
} from '@mui/material';
import SendIcon from '@mui/icons-material/Send';
import LogoutIcon from '@mui/icons-material/Logout';
import PeopleIcon from '@mui/icons-material/People';
import LockIcon from '@mui/icons-material/Lock';
import dayjs from 'dayjs';
import { toast } from 'react-hot-toast';

const ChatPage = () => {
  const navigate = useNavigate();
  const [socket, setSocket] = useState(null);
  const [connected, setConnected] = useState(false);
  const [user, setUser] = useState(null);
  const [messages, setMessages] = useState([]);
  const [inputMessage, setInputMessage] = useState('');
  const [onlineUsers, setOnlineUsers] = useState([]);
  const [currentRoom] = useState('general');
  const [loading, setLoading] = useState(true);
  
  const messagesEndRef = useRef(null);
  const pendingMessages = useRef(new Map()); // Track pending messages

  // Initialize
  useEffect(() => {
    const storedUser = localStorage.getItem('user');
    if (!storedUser) {
      navigate('/login');
      return;
    }

    try {
      const userData = JSON.parse(storedUser);
      setUser(userData);

      const socketInstance = io('http://localhost:5000', {
        transports: ['websocket', 'polling'],
        reconnection: true
      });

      socketInstance.on('connect', () => {
        console.log('✅ Connected');
        setConnected(true);
        
        socketInstance.emit('join', {
          id: userData.id,
          displayName: userData.displayName,
          avatarColor: userData.avatarColor,
          isGuest: userData.isGuest
        });
        
        toast.success('Connected!');
      });

      socketInstance.on('connect_error', (error) => {
        console.error('Connection error:', error);
        setConnected(false);
      });

      // Handle incoming messages from OTHER users
      socketInstance.on('receive_message', (message) => {
        console.log('📥 Message from other user:', message.userName);
        
        // Only add if from another user
        if (message.userId !== userData.id) {
          setMessages(prev => {
            // Check if message already exists (prevent duplicates)
            const exists = prev.some(m => m.id === message.id);
            if (!exists) {
              return [...prev, message];
            }
            return prev;
          });
          
          // Play sound for messages from others
          if (message.userId !== userData.id) {
            playNotificationSound();
          }
        }
      });

      // Handle message confirmation from server
      socketInstance.on('message_confirmation', (confirmation) => {
        console.log('✅ Message confirmed:', confirmation.serverId);
        
        setMessages(prev => prev.map(msg => {
          // Find and update the temporary message
          if (msg.isTemp && msg.message === confirmation.message && msg.userId === userData.id) {
            return {
              ...msg,
              id: confirmation.serverId,
              isTemp: false,
              confirmed: true,
              timestamp: confirmation.timestamp || msg.timestamp
            };
          }
          return msg;
        }));
      });

      socketInstance.on('user_joined', (data) => {
        console.log('👤 User joined:', data.displayName);
        
        setOnlineUsers(prev => {
          const exists = prev.some(u => u.id === data.userId);
          if (!exists) {
            return [...prev, {
              id: data.userId,
              displayName: data.displayName,
              avatarColor: data.avatarColor,
              online: true
            }];
          }
          return prev;
        });
        
        if (data.userId !== userData.id) {
          toast(`${data.displayName} joined`, { icon: '👋', duration: 3000 });
        }
      });

      socketInstance.on('room_info', (roomInfo) => {
        console.log('📋 Room info received');
        setMessages(roomInfo.messages || []);
        setOnlineUsers(roomInfo.users || []);
      });

      socketInstance.on('user_left', (data) => {
        setOnlineUsers(prev => prev.filter(u => u.id !== data.userId));
      });

      setSocket(socketInstance);
      setLoading(false);

      return () => {
        if (socketInstance) {
          socketInstance.disconnect();
        }
      };
    } catch (error) {
      console.error('Error:', error);
      toast.error('Failed to connect');
      navigate('/login');
    }
  }, [navigate]);

  // Send message - NO DUPLICATES
  const sendMessage = () => {
    if (!inputMessage.trim() || !socket || !connected || !user) {
      toast.error('Cannot send message');
      return;
    }

    const tempId = `temp_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
    const messageText = inputMessage.trim();
    
    const messageData = {
      roomId: currentRoom,
      message: messageText,
      userId: user.id,
      userName: user.displayName,
      userColor: user.avatarColor
    };

    console.log('📤 Sending message with temp ID:', tempId);
    
    // Store in pending messages
    pendingMessages.current.set(tempId, messageData);
    
    // Send to server
    socket.emit('send_message', messageData);

    // Add temporary message to UI immediately
    const tempMessage = {
      ...messageData,
      id: tempId,
      timestamp: new Date().toISOString(),
      isTemp: true,
      sending: true
    };

    setMessages(prev => [...prev, tempMessage]);
    setInputMessage('');
  };

  // Play notification sound
  const playNotificationSound = () => {
    try {
      const audio = new Audio('https://assets.mixkit.co/sfx/preview/mixkit-correct-answer-tone-2870.mp3');
      audio.volume = 0.2;
      audio.play();
    } catch (error) {
      console.log('Sound error:', error);
    }
  };

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // Handle key press
  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  // Logout
  const handleLogout = () => {
    localStorage.removeItem('user');
    if (socket) socket.disconnect();
    navigate('/login');
  };

  if (loading) {
    return (
      <Box sx={{ 
        display: 'flex', 
        justifyContent: 'center', 
        alignItems: 'center', 
        height: '100vh',
        flexDirection: 'column',
        gap: 2,
        backgroundColor: '#36393f'
      }}>
        <CircularProgress size={60} sx={{ color: '#7289da' }} />
        <Typography variant="h6" color="white">
          Connecting...
        </Typography>
      </Box>
    );
  }

  return (
    <Box sx={{ display: 'flex', height: '100vh', backgroundColor: '#36393f' }}>
      {/* Left Sidebar */}
      <Paper sx={{ 
        width: 300, 
        height: '100%', 
        display: 'flex', 
        flexDirection: 'column',
        borderRadius: 0,
        backgroundColor: '#2f3136'
      }}>
        {/* User Profile */}
        <Box sx={{ p: 2, borderBottom: '1px solid #40444b' }}>
          <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
            <Avatar sx={{ bgcolor: user?.avatarColor, mr: 2 }}>
              {user?.displayName?.charAt(0)}
            </Avatar>
            <Box sx={{ flexGrow: 1 }}>
              <Typography variant="subtitle1" sx={{ color: 'white', fontWeight: 'bold' }}>
                {user?.displayName}
              </Typography>
              <Chip
                label={connected ? 'Online' : 'Offline'}
                size="small"
                color={connected ? 'success' : 'error'}
                sx={{ height: 20, fontSize: '0.7rem' }}
              />
            </Box>
            <IconButton onClick={handleLogout} size="small" sx={{ color: '#b9bbbe' }}>
              <LogoutIcon />
            </IconButton>
          </Box>
        </Box>

        {/* Online Users */}
        <Box sx={{ p: 2, flexGrow: 1, overflow: 'auto' }}>
          <Typography variant="caption" sx={{ 
            color: '#72767d', 
            fontWeight: 'bold',
            display: 'block',
            mb: 2
          }}>
            ONLINE — {onlineUsers.filter(u => u.id !== user?.id).length}
          </Typography>
          
          <List dense>
            {onlineUsers
              .filter(u => u.id !== user?.id)
              .map((onlineUser) => (
                <ListItem key={onlineUser.id} sx={{ py: 1 }}>
                  <ListItemAvatar>
                    <Badge color="success" variant="dot">
                      <Avatar sx={{ 
                        width: 32, 
                        height: 32,
                        bgcolor: onlineUser.avatarColor 
                      }}>
                        {onlineUser.displayName?.charAt(0)}
                      </Avatar>
                    </Badge>
                  </ListItemAvatar>
                  <ListItemText
                    primary={
                      <Typography variant="body2" sx={{ color: 'white' }}>
                        {onlineUser.displayName}
                      </Typography>
                    }
                  />
                </ListItem>
              ))}
          </List>
        </Box>
      </Paper>

      {/* Main Chat */}
      <Box sx={{ flexGrow: 1, display: 'flex', flexDirection: 'column' }}>
        {/* Chat Header */}
        <Paper sx={{ 
          borderRadius: 0,
          backgroundColor: '#36393f',
          borderBottom: '1px solid #40444b'
        }}>
          <Box sx={{ p: 2, display: 'flex', alignItems: 'center', gap: 2 }}>
            <PeopleIcon sx={{ color: '#b9bbbe' }} />
            <Box sx={{ flexGrow: 1 }}>
              <Typography variant="h6" sx={{ color: 'white' }}>
                General Chat
              </Typography>
              <Typography variant="caption" sx={{ color: '#b9bbbe' }}>
                {onlineUsers.length} users online
              </Typography>
            </Box>
            <Chip
              icon={<LockIcon sx={{ fontSize: 14 }} />}
              label="Encrypted"
              size="small"
              color="success"
              variant="outlined"
            />
          </Box>
        </Paper>

        {/* Messages */}
        <Box sx={{ 
          flexGrow: 1, 
          overflow: 'auto',
          backgroundColor: '#36393f',
          p: 2
        }}>
          {messages.length === 0 ? (
            <Box sx={{ 
              display: 'flex', 
              flexDirection: 'column', 
              alignItems: 'center', 
              justifyContent: 'center',
              height: '100%',
              color: '#72767d',
              textAlign: 'center',
              p: 4
            }}>
              <PeopleIcon sx={{ fontSize: 80, mb: 2, opacity: 0.5 }} />
              <Typography variant="h5" gutterBottom sx={{ color: 'white' }}>
                Start a conversation!
              </Typography>
              <Typography variant="body1" sx={{ maxWidth: 400, mb: 3 }}>
                Send a message to begin chatting with others.
              </Typography>
            </Box>
          ) : (
            <>
              {messages.map((message) => (
                <Box
                  key={message.id}
                  sx={{
                    display: 'flex',
                    justifyContent: message.userId === user?.id ? 'flex-end' : 'flex-start',
                    mb: 2
                  }}
                >
                  {message.userId !== user?.id && (
                    <Avatar
                      sx={{
                        width: 32,
                        height: 32,
                        mr: 1,
                        alignSelf: 'flex-end',
                        bgcolor: message.userColor
                      }}
                    >
                      {message.userName?.charAt(0)}
                    </Avatar>
                  )}
                  
                  <Paper
                    sx={{
                      p: 2,
                      maxWidth: '70%',
                      backgroundColor: message.userId === user?.id ? '#7289da' : '#424549',
                      color: 'white',
                      borderRadius: 2,
                      opacity: message.isTemp ? 0.8 : 1
                    }}
                  >
                    {message.userId !== user?.id && (
                      <Typography variant="caption" sx={{ 
                        color: message.userColor,
                        fontWeight: 'bold',
                        display: 'block',
                        mb: 0.5
                      }}>
                        {message.userName}
                      </Typography>
                    )}
                    
                    <Typography variant="body1" sx={{ wordBreak: 'break-word' }}>
                      {message.message}
                      {message.isTemp && ' • Sending...'}
                    </Typography>
                    
                    <Typography
                      variant="caption"
                      sx={{
                        display: 'block',
                        textAlign: 'right',
                        mt: 0.5,
                        opacity: 0.7,
                        fontSize: '0.75rem'
                      }}
                    >
                      {dayjs(message.timestamp).format('HH:mm')}
                    </Typography>
                  </Paper>
                  
                  {message.userId === user?.id && (
                    <Avatar
                      sx={{
                        width: 32,
                        height: 32,
                        ml: 1,
                        alignSelf: 'flex-end',
                        bgcolor: user.avatarColor
                      }}
                    >
                      {user.displayName?.charAt(0)}
                    </Avatar>
                  )}
                </Box>
              ))}
              <div ref={messagesEndRef} />
            </>
          )}
        </Box>

        {/* Message Input */}
        <Box sx={{ 
          p: 2, 
          backgroundColor: '#36393f',
          borderTop: '1px solid #40444b'
        }}>
          <Box sx={{ display: 'flex', gap: 1, alignItems: 'flex-end' }}>
            <TextField
              fullWidth
              multiline
              maxRows={4}
              placeholder="Type your message..."
              value={inputMessage}
              onChange={(e) => setInputMessage(e.target.value)}
              onKeyPress={handleKeyPress}
              disabled={!connected}
              sx={{
                '& .MuiOutlinedInput-root': {
                  backgroundColor: '#40444b',
                  '& fieldset': { borderColor: 'transparent' },
                  '&:hover fieldset': { borderColor: '#7289da' }
                },
                '& .MuiInputBase-input': { color: 'white' }
              }}
            />
            <IconButton
              onClick={sendMessage}
              disabled={!inputMessage.trim() || !connected}
              sx={{
                backgroundColor: connected ? '#7289da' : '#40444b',
                color: 'white',
                height: 40,
                width: 40
              }}
            >
              <SendIcon />
            </IconButton>
          </Box>
          <Typography variant="caption" sx={{ color: '#72767d', mt: 1, display: 'block' }}>
            {connected ? 'Press Enter to send' : 'Connecting...'}
          </Typography>
        </Box>
      </Box>
    </Box>
  );
};

export default ChatPage;
